parameters.jsCode:
const input = $input.first().json;
const b = input.body || input;

const businessId = b.businessId;
const businessName = b.businessName;
const siteUrl = b.siteUrl;
const category = b.category || 'SaaS';
const description = b.description || '';
const pricing = b.pricing || '29';

if (!businessId || !businessName || !siteUrl) {
  throw new Error('Missing required: businessId, businessName, siteUrl');
}

return [{
  json: {
    businessId,
    businessName,
    siteUrl,
    category,
    description,
    pricing,
    startedAt: new Date().toISOString()
  }
}];

const data = $input.first().json;

const directories = [
  {
    name: 'Capterra',
    task: `Go to capterra.com/vendors/sign-up, fill in the form with:
  Company name: ${data.businessName}
  Website: ${data.siteUrl}
  Category: ${data.category}
  Description: ${data.description}
  Pricing: starts at $${data.pricing}/month
Submit the form.`
  },
  {
    name: 'G2',
    task: `Go to sell.g2.com/create-profile, fill in the form with:
  Product name: ${data.businessName}
  Website: ${data.siteUrl}
  Category: ${data.category}
  Description: ${data.description}
  Pricing: starts at $${data.pricing}/month
Submit the form.`
  },
  {
    name: 'GetApp',
    task: `Go to getapp.com/submit, fill in the form with:
  Company name: ${data.businessName}
  Website: ${data.siteUrl}
  Category: ${data.category}
  Description: ${data.description}
  Pricing: starts at $${data.pricing}/month
Submit the form.`
  },
  {
    name: 'Software Advice',
    task: `Go to softwareadvice.com/vendors, fill in the form with:
  Company name: ${data.businessName}
  Website: ${data.siteUrl}
  Category: ${data.category}
  Description: ${data.description}
  Pricing: starts at $${data.pricing}/month
Submit the form.`
  },
  {
    name: 'Product Hunt',
    task: `Go to producthunt.com/posts/new, fill in the form with:
  Product name: ${data.businessName}
  Website: ${data.siteUrl}
  Tagline: ${data.description.substring(0, 60)}
  Description: ${data.description}
Submit the form.`
  },
  {
    name: 'AlternativeTo',
    task: `Go to alternativeto.net/add-app, fill in the form with:
  App name: ${data.businessName}
  Website: ${data.siteUrl}
  Category: ${data.category}
  Description: ${data.description}
Submit the form.`
  },
  {
    name: 'SaaSHub',
    task: `Go to saashub.com/submit, fill in the form with:
  Product name: ${data.businessName}
  Website: ${data.siteUrl}
  Category: ${data.category}
  Description: ${data.description}
  Pricing: starts at $${data.pricing}/month
Submit the form.`
  }
];

return directories.map(d => ({
  json: {
    ...data,
    directoryName: d.name,
    browserTask: d.task
  }
}));

const result = $input.first().json;
const directory = $('Build Directory Tasks').first().json.directoryName;
const businessName = $('Build Directory Tasks').first().json.businessName;

const success = result.status === 'completed' || result.status === 'success';
const error = result.error || result.message || null;

return [{
  json: {
    directory,
    businessName,
    success,
    error,
    result: success ? 'submitted' : 'failed',
    details: error || 'Submission completed'
  }
}];

const items = $input.all();
const businessName = items[0]?.json?.businessName || 'Unknown';

const results = items.map(i => i.json);
const succeeded = results.filter(r => r.success);
const failed = results.filter(r => !r.success);

const report = {
  businessName,
  totalDirectories: results.length,
  successCount: succeeded.length,
  failCount: failed.length,
  succeeded: succeeded.map(r => r.directory),
  failed: failed.map(r => ({ directory: r.directory, error: r.error || r.details })),
  timestamp: new Date().toISOString()
};

let reportText = `Directory Submission Report for ${businessName}\n`;
reportText += `================================\n`;
reportText += `Submitted: ${succeeded.length}/${results.length}\n\n`;

if (succeeded.length > 0) {
  reportText += `Successful:\n${succeeded.map(r => `  - ${r.directory}`).join('\n')}\n\n`;
}

if (failed.length > 0) {
  reportText += `Failed (need manual submission):\n${failed.map(r => `  - ${r.directory}: ${r.error || r.details}`).join('\n')}\n`;
}

return [{
  json: {
    ...report,
    reportText
  }
}];

const data = $input.first().json;
const failed = data.failed || [];

const body = `## Manual Directory Submission Required\n\n` +
  `Business: **${data.businessName}**\n\n` +
  `The following directories failed automated submission and need manual attention:\n\n` +
  failed.map(f => `- **${f.directory}**: ${f.error}`).join('\n') + '\n\n' +
  `### Submission Details\n` +
  `Use the business info from the memory-bank to fill in directory forms.\n\n` +
  `Generated: ${data.timestamp}`;

return [{
  json: {
    owner: 'Sluice-Organization',
    repo: 'sluice-orchestration',
    title: '[Manual] Directory submissions needed for ' + data.businessName,
    body,
    labels: ['manual-submission', 'distribution']
  }
}];

